<script setup lang="ts">const schoolModules=useSchoolModules();await schoolModules.ready;const{modules}=schoolModules;const active=ref('');const categories=computed(()=>modules.value.studentCategories.filter(item=>item.status==='published'));const items=computed(()=>modules.value.studentActivities.filter(item=>item.status==='published'&&(!active.value||item.categoryId===active.value)));useSchoolSeo('Kesiswaan','Kegiatan siswa SD Negeri Sukorame 2')</script>
<template><div><section class="bg-school-sky py-14"><div class="container-school"><p class="font-hand text-2xl font-bold text-school-action">Kesiswaan</p><h1 class="font-display mt-2 text-5xl text-school-navy">Kegiatan Siswa</h1><div class="mt-6 flex flex-wrap gap-2"><button class="btn btn-secondary" @click="active=''">Semua</button><button v-for="category in categories" :key="category.id" class="btn btn-secondary" @click="active=category.id">{{category.name}}</button></div></div></section><div class="container-school grid gap-6 py-12 md:grid-cols-2 lg:grid-cols-3"><article v-for="item in items" :key="item.id" class="card overflow-hidden"><div class="flex snap-x overflow-x-auto"><img v-for="(image,index) in item.images" :key="index" :src="image" :alt="item.title" class="aspect-[4/3] w-full shrink-0 snap-center object-cover"><img v-if="!item.images.length" src="https://cdn.sdnsukorame2kotakediri.sch.id/images/no-image.png" alt="Belum ada gambar" class="aspect-[4/3] w-full object-contain"></div><div class="p-5"><p class="text-xs text-muted">{{new Date(item.date).toLocaleDateString('id-ID',{dateStyle:'long',timeZone:'Asia/Jakarta'})}}</p><h2 class="mt-2 text-xl font-bold text-school-navy">{{item.title}}</h2><p class="mt-3 text-sm leading-6 text-muted">{{item.description}}</p></div></article><p v-if="!items.length" class="text-muted">Belum ada kegiatan terbit.</p></div></div></template>
